const startDate = 484759;
var nowPrice = price[Math.floor(Date.now() / 3600000 - startDate)];

console.log(nowPrice)
document.getElementById('price').innerHTML = nowPrice + '$'

var balance;
if (localStorage.getItem("balance")) {
    balance = Number(localStorage.getItem("balance"));
} else {
    localStorage.setItem("balance", 100);
    balance = 100;
}
document.getElementById('balance').innerHTML = balance.toFixed(4) + '$'

localStorage.setItem("onBalance", 0);
var onBalance = localStorage.getItem("onBalance");
document.getElementById('onBalance').innerHTML = onBalance

var maxPrice = price[0];
var minPrice = price[0];
for (let i = 1; i <= Math.floor(Date.now() / 3600000 - startDate); i++) {
    if (maxPrice < price[i]) {
        maxPrice = price[i]
    }
    if (minPrice > price[i]) {
        minPrice = price[i]
    }
}
document.getElementById('maxPrice').innerHTML = maxPrice + '$'
document.getElementById('minPrice').innerHTML = minPrice + '$'

function buy() {
    var ans = Number(prompt("How many YarikCoin do you want to buy? For the full balance you can buy " + (balance / nowPrice).toFixed(4) + " YarikCoin."));
    if (!(ans == ans.toString())) {
        return alert("Enter a number!");
    }
    if (ans * nowPrice > balance) {
        return alert("You don’t have enough balance!");
    }    
    localStorage.setItem("onBalance", Number(onBalance) + ans);
    onBalance = localStorage.getItem("onBalance");
    balance -= ans * nowPrice;
    localStorage.setItem("balance", balance);
    document.getElementById('balance').innerHTML = balance.toFixed(4) + '$';
    document.getElementById('onBalance').innerHTML = onBalance;
}

function sell() {
    var ans = Number(prompt("How many YarikCoin do you want to sell? If you sell all YarikCoin, you will get " + (onBalance * nowPrice).toFixed(4) + "$"));
    if (!(ans == ans.toString())) {
        return alert("Enter a number!");
    }
    if (ans > onBalance) {
        return alert("You don’t have enough YarikCoin!");
    }    
    if (ans == 0) {
        return;
    }
    localStorage.setItem("onBalance", onBalance - ans);
    onBalance = localStorage.getItem("onBalance");
    localStorage.setItem("balance", Number(balance) + ans * nowPrice);
    balance = localStorage.getItem("balance");
    document.getElementById('balance').innerHTML = Number(balance).toFixed(4) + '$';
    document.getElementById('onBalance').innerHTML = onBalance;
    console.log(ans);
    console.log(ans == "NaN");
}

document.getElementById('buy').addEventListener("click", buy)
document.getElementById('sell').addEventListener("click", sell)